+const JUDGE_IDLE_FRAMES = [
+  JUDGE_SPRITE,
+  [' '.repeat(JUDGE_SPRITE[0].length), ...JUDGE_SPRITE.slice(0, JUDGE_SPRITE.length - 1)],
+  JUDGE_SPRITE.map(line => line.replace('O', '0')),
+  JUDGE_SPRITE,
+];
+
+const BLACKSMITH_IDLE_FRAMES = [
+  BLACKSMITH_SPRITE,
+  [' '.repeat(BLACKSMITH_SPRITE[0].length), ...BLACKSMITH_SPRITE.slice(0, BLACKSMITH_SPRITE.length - 1)],
+  BLACKSMITH_SPRITE.map(line => line.replace('O', '0')),
+  // hammer sway right: shift 'M' chars right by 1 in lines 8 and 9
+  BLACKSMITH_SPRITE.map((line, i) => {
+    if (i === 8 || i === 9) {
+      let chars = line.split('');
+      for (let idx = chars.length - 2; idx >= 0; idx--) {
+        if (chars[idx] === 'M') {
+          chars[idx] = ' ';
+          chars[idx + 1] = 'M';
+        }
+      }
+      return chars.join('');
+    }
+    return line;
+  }),
+  // hammer sway left: shift 'M' chars left by 1 in lines 8 and 9
+  BLACKSMITH_SPRITE.map((line, i) => {
+    if (i === 8 || i === 9) {
+      let chars = line.split('');
+      for (let idx = 1; idx < chars.length; idx++) {
+        if (chars[idx] === 'M') {
+          chars[idx] = ' ';
+          chars[idx - 1] = 'M';
+        }
+      }
+      return chars.join('');
+    }
+    return line;
+  }),
+];
+
+const IDLE_FRAMES_MAP: Record<CharacterType, string[][]> = {
+  king: KING_IDLE_FRAMES,
+  knight: KNIGHT_IDLE_FRAMES,
+  healer: HEALER_IDLE_FRAMES,
+  sentinel: SENTINEL_IDLE_FRAMES,
+  nobility: NOBILITY_IDLE_FRAMES,
+  squire: SQUIRE_IDLE_FRAMES,
+  scribe: SCRIBE_IDLE_FRAMES,
+  judge: JUDGE_IDLE_FRAMES,
+  blacksmith: BLACKSMITH_IDLE_FRAMES,
+};
+
+const IDLE_FRAME_DURATION = 200;
+
+const MEDIEVAL_QUIPS = [
+  "Hark!",
+  "By my troth!",
+  "Fie on't!",
+  "Zounds!",
+  "Gramercy!",
+  "Prithee!",
+  "Forsooth!",
+  "Marry!",
+  "Anon!",
+  "Alack!",
+];
+
+let bubbleTimeouts = new Map<Character, number>();
+
+function updateBubble(character: Character) {
+  if (bubbleTimeouts.has(character)) {
+    clearTimeout(bubbleTimeouts.get(character));
+  }
+  bubbleTimeouts.set(character, window.setTimeout(() => {
+    character.bubbleText = "";
+    bubbleTimeouts.delete(character);
+  }, 3000));
+}
+
+function drawBubble(ctx: CanvasRenderingContext2D, x: number, y: number, text: string) {
+  if (!text) return;
+  const paddingX = 6;
+  const paddingY = 4;
+  ctx.font = "10px monospace";
+  const lines = text.split('\n');
+  const lineHeight = 12;
+  let maxWidth = 0;
+  for (const line of lines) {
+    const w = ctx.measureText(line).width;
+    if (w > maxWidth) maxWidth = w;
+  }
+  const width = maxWidth + paddingX * 2;
+  const height = lines.length * lineHeight + paddingY * 2;
+
+  // Bubble position above character
+  const bubbleX = x - width / 2;
+  const bubbleY = y - height - 14;
+
+  // Draw rounded rect bubble
+  const radius = 6;
+  ctx.fillStyle = "white";
+  ctx.strokeStyle = "#222";
+  ctx.lineWidth = 1;
+  ctx.beginPath();
+  ctx.moveTo(bubbleX + radius, bubbleY);
+  ctx.lineTo(bubbleX + width - radius, bubbleY);
+  ctx.quadraticCurveTo(bubbleX + width, bubbleY, bubbleX + width, bubbleY + radius);
+  ctx.lineTo(bubbleX + width, bubbleY + height - radius);
+  ctx.quadraticCurveTo(bubbleX + width, bubbleY + height, bubbleX + width - radius, bubbleY + height);
+
+  // Pointer triangle
+  const pointerX = x;
+  const pointerY = bubbleY + height;
+  ctx.lineTo(pointerX + 6, pointerY);
+  ctx.lineTo(pointerX, pointerY + 8);
+  ctx.lineTo(pointerX - 6, pointerY);
+
+  ctx.lineTo(bubbleX + radius, bubbleY + height);
+  ctx.quadraticCurveTo(bubbleX, bubbleY + height, bubbleX, bubbleY + height - radius);
+  ctx.lineTo(bubbleX, bubbleY + radius);
+  ctx.quadraticCurveTo(bubbleX, bubbleY, bubbleX + radius, bubbleY);
+  ctx.closePath();
+  ctx.fill();
+  ctx.stroke();
+
+  // Draw text lines
+  ctx.fillStyle = "#222";
+  ctx.textBaseline = "top";
+  for (let i = 0; i < lines.length; i++) {
+    ctx.fillText(lines[i], bubbleX + paddingX, bubbleY + paddingY + i * lineHeight);
+  }
+}
+
+function drawCharacter(character: Character, ctx: CanvasRenderingContext2D, x: number, y: number) {
+  const frames = IDLE_FRAMES_MAP[character.type];
+  const now = Date.now();
+  const frameIndex = Math.floor(now / IDLE_FRAME_DURATION) % frames.length;
+  const frame = frames[frameIndex];
+
+  // Draw character sprite (existing code assumed)
+  for (let i = 0; i < frame.length; i++) {
+    const line = frame[i];
+    for (let j = 0; j < line.length; j++) {
+      const ch = line[j];
+      if (ch !== ' ') {
+        ctx.fillStyle = "#000";
+        ctx.fillText(ch, x + j * 8, y + i * 10);
+      }
+    }
+  }
+
+  // Determine bubble text
+  let bubbleText = "";
+  if (character.currentTask && character.currentTask.title) {
+    bubbleText = character.currentTask.title;
+  } else {
+    // Random quip from medieval quips
+    if (!character.bubbleText || character.bubbleText === "") {
+      const idx = Math.floor(Math.random() * MEDIEVAL_QUIPS.length);
+      bubbleText = MEDIEVAL_QUIPS[idx];
+      character.bubbleText = bubbleText;
+      updateBubble(character);
+    } else {
+      bubbleText = character.bubbleText;
+    }
+  }
+
+  drawBubble(ctx, x + 16, y, bubbleText);
+}
